import pytest
from queue import Queue, Empty
from concurrent.futures import Future, ThreadPoolExecutor
from unittest.mock import Mock
from more_itertools import *
from more_itertools.more import *


class AbortThread(Exception):
    pass

class TestReader:
    def setup_method(self):
        self.executor = ThreadPoolExecutor()
        self.callback_kwd = 'callback'
        self.wait_seconds = 1
        self.aborted = False
        self.func = Mock()
        self.reader = self._reader_setup()

    def _reader_setup(self):
        class Reader:
            def __init__(self, func, executor, callback_kwd, wait_seconds):
                self._func = func
                self._executor = executor
                self._callback_kwd = callback_kwd
                self._wait_seconds = wait_seconds
                self._aborted = False
                self._future = None

            def _reader(self):
                q = Queue()

                def callback(*args, **kwargs):
                    if self._aborted:
                        raise AbortThread('canceled by user')
                    q.put((args, kwargs))

                self._future = self._executor.submit(
                    self._func, **{self._callback_kwd: callback}
                )

                while True:
                    try:
                        item = q.get(timeout=self._wait_seconds)
                    except Empty:
                        pass
                    else:
                        q.task_done()
                        yield item

                    if self._future.done():
                        break

                remaining = []
                while True:
                    try:
                        item = q.get_nowait()
                    except Empty:
                        break
                    else:
                        q.task_done()
                        remaining.append(item)
                q.join()
                yield from remaining

        return Reader(self.func, self.executor, self.callback_kwd, self.wait_seconds)

    def test_normal_case(self):
        def test_func(callback):
            callback('item1')
            callback('item2')

        self.reader._func = test_func
        items = list(self.reader._reader())
        assert items == [(('item1',), {}), (('item2',), {})]

    def test_no_items(self):
        def test_func(callback):
            pass  # No items added

        self.reader._func = test_func
        items = list(self.reader._reader())
        assert items == []

    def test_aborted_case(self):
        def test_func(callback):
            callback('item1')

        self.reader._func = test_func
        self.reader._aborted = True
        with pytest.raises(AbortThread):
            list(self.reader._reader())

    def test_empty_queue_timeout(self):
        def test_func(callback):
            pass  # No items added

        self.reader._func = test_func
        items = list(self.reader._reader())
        assert items == []

    def test_future_done_before_items(self):
        def test_func(callback):
            pass  # No items added

        self.reader._func = test_func
        items = list(self.reader._reader())
        assert items == []

    def test_zero_wait_seconds(self):
        def test_func(callback):
            callback('item1')

        self.reader._func = test_func
        self.reader._wait_seconds = 0  # Immediate timeout
        items = list(self.reader._reader())
        assert items == []

    def teardown_method(self):
        self.executor.shutdown(wait=True)

