import pytest
from itertools import cycle, count, product, zip_longest, repeat
from more_itertools import *
from more_itertools.more import *


def count_cycle(iterable, n=None):
    """Cycle through the items from *iterable* up to *n* times, yielding
    the number of completed cycles along with each item. If *n* is omitted the
    process repeats indefinitely.
    """
    if n is not None:
        return product(range(n), iterable)
    seq = tuple(iterable)
    if not seq:
        return iter(())
    counter = count() if n is None else range(n)
    return zip(repeat_each(counter, len(seq)), cycle(seq))

def repeat_each(counter, length):
    """Helper function to repeat each count for the length of the iterable."""
    for count in counter:
        for _ in range(length):
            yield count

# Unit tests
def test_basic_cycling():
    result = list(count_cycle('AB', 3))
    expected = [(0, 'A'), (0, 'B'), (1, 'A'), (1, 'B'), (2, 'A'), (2, 'B')]
    assert result == expected

def test_indefinite_cycling():
    result = list(count_cycle('AB'))
    expected = [(0, 'A'), (0, 'B'), (1, 'A'), (1, 'B')]  # This will be infinite, so we limit the output
    assert result[:4] == expected

def test_multiple_cycles():
    result = list(count_cycle([1, 2, 3], 2))
    expected = [(0, 1), (0, 2), (0, 3), (1, 1), (1, 2), (1, 3)]
    assert result == expected

def test_empty_iterable():
    result = list(count_cycle([], 3))
    expected = []
    assert result == expected

def test_single_item_iterable():
    result = list(count_cycle(['X'], 3))
    expected = [(0, 'X'), (1, 'X'), (2, 'X')]
    assert result == expected

def test_zero_cycles():
    result = list(count_cycle('AB', 0))
    expected = []
    assert result == expected

def test_negative_cycles():
    with pytest.raises(ValueError):
        list(count_cycle('AB', -1))

def test_large_n():
    result = list(count_cycle('A', 1000))  # Should just repeat 'A' 1000 times
    expected = [(i, 'A') for i in range(1000)]
    assert result == expected

def test_non_iterable_input():
    with pytest.raises(TypeError):
        list(count_cycle(123, 3))

