import pytest
from more_itertools import *
from more_itertools.more import *


# Mock wrapping function for testing
def wrapping_func(*args, **kwargs):
    return args, kwargs

# Mock result_index for testing
result_index = 0

# The decorator function with the necessary modifications
def decorator(*wrapping_args, **wrapping_kwargs):
    def outer_wrapper(f):
        def inner_wrapper(*args, **kwargs):
            result = f(*args, **kwargs)
            wrapping_args_ = list(wrapping_args)
            wrapping_args_.insert(result_index, result)
            return wrapping_func(*wrapping_args_, **wrapping_kwargs)

        return inner_wrapper

    return outer_wrapper

# Test cases
def test_decorator_with_simple_return():
    @decorator(1, 2, 3)
    def simple_function():
        return 5

    assert simple_function() == ((5, 1, 2, 3), {})

def test_decorator_with_args():
    @decorator('a', 'b')
    def add(a, b):
        return a + b

    assert add(2, 3) == ((5, 'a', 'b'), {})

def test_decorator_with_string_return():
    @decorator('hello')
    def greet(name):
        return f"Hello, {name}"

    assert greet("World") == (("Hello, World", 'hello'), {})

def test_decorator_with_list_return():
    @decorator(1, 2)
    def return_list():
        return [1, 2, 3]

    assert return_list() == (([1, 2, 3], 1, 2), {})

