    @decorator()
    def return_none():
        return None

    assert return_none() == ((None,), {})

def test_decorator_with_invalid_index():
    global result_index
    result_index = 5  # Out of bounds
    @decorator(1, 2)
    def return_value():
        return 3

    with pytest.raises(IndexError):
        return_value()

def test_decorator_with_no_arguments():
    @decorator()
    def no_args_function():
        return 42

    assert no_args_function() == ((42,), {})

