import pytest
from unittest.mock import Mock, MagicMock
from queue import Queue, Empty
from concurrent.futures import Future
import time
from more_itertools import *
from more_itertools.more import *


class AbortThread(Exception):
    pass

class TestReader:
    @pytest.fixture
    def setup_reader(self):
        class Reader:
            def __init__(self):
                self._aborted = False
                self._executor = Mock()
                self._func = Mock()
                self._callback_kwd = 'callback'
                self._wait_seconds = 1
                self._future = Future()

            def _reader(self):
                q = Queue()

                def callback(*args, **kwargs):
                    if self._aborted:
                        raise AbortThread('canceled by user')
                    q.put((args, kwargs))

                self._future = self._executor.submit(
                    self._func, **{self._callback_kwd: callback}
                )

                while True:
                    try:
                        item = q.get(timeout=self._wait_seconds)
                    except Empty:
                        pass
                    else:
                        q.task_done()
                        yield item

                    if self._future.done():
                        break

                remaining = []
                while True:
                    try:
                        item = q.get_nowait()
                    except Empty:
                        break
                    else:
                        q.task_done()
                        remaining.append(item)
                q.join()
                yield from remaining

        return Reader()

    def test_normal_operation(self, setup_reader):
        reader = setup_reader
        reader._func = lambda callback: [callback(i) for i in range(5)]
        reader._future.set_result(None)  # Mark future as done

        items = list(reader._reader())
        assert items == [((0,), {}), ((1,), {}), ((2,), {}), ((3,), {}), ((4,), {})]

    def test_empty_queue(self, setup_reader):
        reader = setup_reader
        reader._func = lambda callback: None  # No items added
        reader._future.set_result(None)

        items = list(reader._reader())
        assert items == []

    def test_aborted_operation(self, setup_reader):
        reader = setup_reader
        reader._aborted = True
        reader._func = lambda callback: [callback(i) for i in range(5)]

        with pytest.raises(AbortThread):
            list(reader._reader())

    def test_callback_exception(self, setup_reader):
        reader = setup_reader
        reader._func = lambda callback: [callback(i) for i in range(5)]
        reader._future.set_result(None)

        def callback(*args, **kwargs):
            if args[0] == 2:
                raise ValueError("Error in callback")
            return args

        reader._executor.submit = Mock(side_effect=lambda func, **kwargs: func(callback))

        with pytest.raises(ValueError, match="Error in callback"):
            list(reader._reader())

    def test_timeout_zero(self, setup_reader):
        reader = setup_reader
        reader._wait_seconds = 0  # Set timeout to zero
        reader._func = lambda callback: [callback(i) for i in range(5)]
        reader._future.set_result(None)

        items = list(reader._reader())
        assert items == [((0,), {}), ((1,), {}), ((2,), {}), ((3,), {}), ((4,), {})]

    def test_large_number_of_items(self, setup_reader):
        reader = setup_reader
        reader._func = lambda callback: [callback(i) for i in range(1000)]
        reader._future.set_result(None)

        items = list(reader._reader())
        assert len(items) == 1000
        assert items == [((i,), {}) for i in range(1000)]

