class TestDeregisterHook:
    @pytest.fixture
    def hook_manager(self):
        class HookManager:
            def __init__(self):
                self.hooks = {}

            def register_hook(self, event, hook):
                if event not in self.hooks:
                    self.hooks[event] = []
                self.hooks[event].append(hook)

            def deregister_hook(self, event, hook):
                """Deregister a previously registered hook.
                Returns True if the hook existed, False if not.
                """
                try:
                    self.hooks[event].remove(hook)
                    return True
                except ValueError:
                    return False

        return HookManager()

    def test_deregister_existing_hook(self, hook_manager):
        hook_manager.register_hook('event1', 'hook1')
        assert hook_manager.deregister_hook('event1', 'hook1') is True
        assert 'hook1' not in hook_manager.hooks['event1']

    def test_deregister_non_existing_hook(self, hook_manager):
        hook_manager.register_hook('event1', 'hook1')
        assert hook_manager.deregister_hook('event1', 'hook2') is False

    def test_deregister_hook_from_nonexistent_event(self, hook_manager):
        assert hook_manager.deregister_hook('event2', 'hook1') is False

    def test_deregister_multiple_hooks(self, hook_manager):
        hook_manager.register_hook('event1', 'hook1')
        hook_manager.register_hook('event1', 'hook2')
        assert hook_manager.deregister_hook('event1', 'hook1') is True
        assert 'hook1' not in hook_manager.hooks['event1']
        assert 'hook2' in hook_manager.hooks['event1']

    def test_deregister_hook_after_multiple_registrations(self, hook_manager):
        hook_manager.register_hook('event1', 'hook1')
        hook_manager.register_hook('event1', 'hook1')  # Registering the same hook again
        assert hook_manager.deregister_hook('event1', 'hook1') is True
        assert hook_manager.deregister_hook('event1', 'hook1') is True  # Should still be able to deregister

    def test_deregister_hook_with_empty_hooks(self, hook_manager):
        assert hook_manager.deregister_hook('event1', 'hook1') is False  # No hooks registered

    def test_deregister_hook_with_none(self, hook_manager):
        hook_manager.register_hook('event1', None)
        assert hook_manager.deregister_hook('event1', None) is True
        assert None not in hook_manager.hooks['event1']

