import pytest
from datetime import datetime, timezone, timedelta

from zoneinfo import ZoneInfo, ZoneInfoNotFoundError
from arrow.parser import DateTimeParser, ParserError, ParserMatchError
from arrow import parser


class TestParse:

    def test_parse_local_timezone(self):
        tzinfo = parse("local")
        assert tzinfo is not None
        assert tzinfo.utcoffset(datetime.now()) is not None

    def test_parse_utc_timezone(self):
        tzinfo = parse("utc")
        assert tzinfo == timezone.utc

    def test_parse_uppercase_utc_timezone(self):
        tzinfo = parse("UTC")
        assert tzinfo == timezone.utc

    def test_parse_z_timezone(self):
        tzinfo = parse("Z")
        assert tzinfo == timezone.utc

    def test_parse_iso_timezone_positive(self):
        tzinfo = parse("+05:30")
        assert tzinfo.utcoffset(datetime.now()) == timedelta(hours=5, minutes=30)

    def test_parse_iso_timezone_negative(self):
        tzinfo = parse("-02:00")
        assert tzinfo.utcoffset(datetime.now()) == timedelta(hours=-2)

    def test_parse_iso_timezone_without_minutes(self):
        tzinfo = parse("+05")
        assert tzinfo.utcoffset(datetime.now()) == timedelta(hours=5)

    def test_parse_invalid_iso_timezone(self):
        with pytest.raises(ParserError):
            parse("+99:99")

    def test_parse_zoneinfo_timezone(self):
        tzinfo = parse("America/New_York")
        assert isinstance(tzinfo, ZoneInfo)

    def test_parse_invalid_zoneinfo_timezone(self):
        with pytest.raises(ParserError):
            parse("Invalid/Timezone")

    def test_parse_none_timezone_string(self):
        with pytest.raises(ParserError):
            parse(None)

    def test_parse_empty_timezone_string(self):
        with pytest.raises(ParserError):
            parse("")

    def test_parse_invalid_timezone_string(self):
        with pytest.raises(ParserError):
            parse("NotATimezone")

