@pytest.fixture
def custom_peek(iterator_with_items):
    class CustomPeek:
        def __init__(self, it):
            self._it = it
            self._cache = []

        def peek(self, default=_marker):
            if not self._cache:
                try:
                    self._cache.append(next(self._it))
                except StopIteration:
                    if default is _marker:
                        raise
                    return default
            return self._cache[0]

    return CustomPeek(iterator_with_items)

def test_peek_next_item(custom_peek):
    assert custom_peek.peek() == 1

def test_peek_multiple_calls(custom_peek):
    assert custom_peek.peek() == 1
    assert custom_peek.peek() == 1  # Should still return the same item

def test_peek_after_next(custom_peek):
    custom_peek.peek()  # Cache the first item
    next(custom_peek)    # Move to the next item
    assert custom_peek.peek() == 2  # Now it should return the next item

def test_peek_empty_iterator(empty_iterator):
    custom_peek_empty = CustomPeek(empty_iterator)
    with pytest.raises(StopIteration):
        custom_peek_empty.peek()

def test_peek_empty_iterator_with_default(empty_iterator):
    custom_peek_empty = CustomPeek(empty_iterator)
    assert custom_peek_empty.peek(default='default_value') == 'default_value'

def test_peek_after_exhaustion_with_default(custom_peek):
    custom_peek.peek()  # Cache the first item
    next(custom_peek)    # Move to the next item
