import pytest
from itertools import islice
from sys import maxsize
from more_itertools import *
from more_itertools.more import *


class TestSlice:
    @pytest.fixture
    def slice_instance(self):
        class SliceInstance:
            def __init__(self, iterable):
                self._it = iterable
                self._cache = []

            def _get_slice(self, index):
                step = 1 if (index.step is None) else index.step
                if step > 0:
                    start = 0 if (index.start is None) else index.start
                    stop = maxsize if (index.stop is None) else index.stop
                elif step < 0:
                    start = -1 if (index.start is None) else index.start
                    stop = (-maxsize - 1) if (index.stop is None) else index.stop
                else:
                    raise ValueError('slice step cannot be zero')

                if (start < 0) or (stop < 0):
                    self._cache.extend(self._it)
                else:
                    n = min(max(start, stop) + 1, maxsize)
                    cache_len = len(self._cache)
                    if n >= cache_len:
                        self._cache.extend(islice(self._it, n - cache_len))

                return list(self._cache)[index]

        return SliceInstance(range(10))

    def test_get_slice_positive_step(self, slice_instance):
        assert slice_instance._get_slice(slice(2, 5)) == [2, 3, 4]

    def test_get_slice_negative_step(self, slice_instance):
        assert slice_instance._get_slice(slice(5, 2, -1)) == [5, 4, 3]

    def test_get_slice_with_none_start(self, slice_instance):
        assert slice_instance._get_slice(slice(None, 5)) == [0, 1, 2, 3, 4]

    def test_get_slice_with_none_stop(self, slice_instance):
        assert slice_instance._get_slice(slice(5, None)) == [5, 6, 7, 8, 9]

    def test_get_slice_empty_cache(self, slice_instance):
        slice_instance._cache = []
        assert slice_instance._get_slice(slice(0, 3)) == [0, 1, 2]

    def test_get_slice_negative_start(self, slice_instance):
        assert slice_instance._get_slice(slice(-3, None)) == [7, 8, 9]

    def test_get_slice_zero_step(self, slice_instance):
        with pytest.raises(ValueError, match='slice step cannot be zero'):
            slice_instance._get_slice(slice(0, 5, 0))

    def test_get_slice_full_range(self, slice_instance):
        assert slice_instance._get_slice(slice(None, None)) == list(range(10))

    def test_get_slice_large_range(self, slice_instance):
        assert slice_instance._get_slice(slice(0, 15)) == list(range(10))

    def test_get_slice_negative_indices(self, slice_instance):
        assert slice_instance._get_slice(slice(-1, -3)) == [9]

    def test_get_slice_with_step(self, slice_instance):
        assert slice_instance._get_slice(slice(0, 10, 2)) == [0, 2, 4, 6, 8]

