class MockResponse:
    def __init__(self, status_code, reason, url):
        self.status_code = status_code
        self.reason = reason
        self.url = url

    def raise_for_status(self):
        """Raises :class:`HTTPError`, if one occurred."""
        http_error_msg = ""
        if isinstance(self.reason, bytes):
            try:
                reason = self.reason.decode("utf-8")
            except UnicodeDecodeError:
                reason = self.reason.decode("iso-8859-1")
        else:
            reason = self.reason

        if 400 <= self.status_code < 500:
            http_error_msg = (
                f"{self.status_code} Client Error: {reason} for url: {self.url}"
            )

        elif 500 <= self.status_code < 600:
            http_error_msg = (
                f"{self.status_code} Server Error: {reason} for url: {self.url}"
            )

        if http_error_msg:
            raise HTTPError(http_error_msg, response=self)

def test_raise_for_status_client_error():
    response = MockResponse(404, b"Not Found", "http://example.com")
    with pytest.raises(HTTPError) as excinfo:
        response.raise_for_status()
    assert str(excinfo.value) == "404 Client Error: Not Found for url: http://example.com"

def test_raise_for_status_server_error():
    response = MockResponse(500, b"Internal Server Error", "http://example.com")
    with pytest.raises(HTTPError) as excinfo:
        response.raise_for_status()
    assert str(excinfo.value) == "500 Server Error: Internal Server Error for url: http://example.com"

def test_raise_for_status_utf8_decoding():
    response = MockResponse(400, b"Bad Request", "http://example.com")
    with pytest.raises(HTTPError) as excinfo:
        response.raise_for_status()
    assert str(excinfo.value) == "400 Client Error: Bad Request for url: http://example.com"

def test_raise_for_status_iso8859_decoding():
    response = MockResponse(400, b"\xC3\xA9", "http://example.com")  # é in bytes
    with pytest.raises(HTTPError) as excinfo:
        response.raise_for_status()
    assert str(excinfo.value) == "400 Client Error: é for url: http://example.com"

def test_raise_for_status_no_error():
    response = MockResponse(200, b"OK", "http://example.com")
    try:
        response.raise_for_status()
    except HTTPError:
        pytest.fail("HTTPError raised unexpectedly!")

def test_raise_for_status_non_bytes_reason():
    response = MockResponse(403, "Forbidden", "http://example.com")
    with pytest.raises(HTTPError) as excinfo:
        response.raise_for_status()
    assert str(excinfo.value) == "403 Client Error: Forbidden for url: http://example.com"

def test_raise_for_status_empty_reason():
    response = MockResponse(404, b"", "http://example.com")
    with pytest.raises(HTTPError) as excinfo:
        response.raise_for_status()
    assert str(excinfo.value) == "404 Client Error:  for url: http://example.com"

