class MockResponse:
    def __init__(self, content, encoding=None, apparent_encoding=None):
        self.content = content
        self.encoding = encoding
        self.apparent_encoding = apparent_encoding

    def text(self):
        """Content of the response, in unicode."""
        content = None
        encoding = self.encoding

        if not self.content:
            return ""

        if self.encoding is None:
            encoding = self.apparent_encoding

        try:
            content = str(self.content, encoding, errors="replace")
        except (LookupError, TypeError):
            content = str(self.content, errors="replace")

        return content

def test_text_with_valid_encoding():
    response = MockResponse(b'Hello, world!', encoding='utf-8')
    assert response.text() == 'Hello, world!'

def test_text_with_none_encoding_and_apparent_encoding():
    response = MockResponse(b'Hello, world!', apparent_encoding='utf-8')
    assert response.text() == 'Hello, world!'

def test_text_with_none_content():
    response = MockResponse(b'')
    assert response.text() == ''

def test_text_with_invalid_encoding():
    response = MockResponse(b'Hello, world!', encoding='invalid-encoding')
    assert response.text() == 'Hello, world!'  # Should replace invalid chars

def test_text_with_type_error_on_encoding():
    response = MockResponse(b'Hello, world!', encoding=None)
    response.apparent_encoding = None  # Simulate TypeError scenario
    assert response.text() == 'Hello, world!'  # Should replace invalid chars

def test_text_with_empty_bytes():
    response = MockResponse(b'')
    assert response.text() == ''

def test_text_with_non_bytes_content():
    response = MockResponse("Hello, world!", encoding='utf-8')
    assert response.text() == "Hello, world!"  # Should handle string input

def test_text_with_mixed_content():
    response = MockResponse(b'Hello, \xe9', encoding='latin-1')
    assert response.text() == 'Hello, é'  # Should decode correctly

def test_text_with_replacement_on_invalid_bytes():
    response = MockResponse(b'Hello, \xff', encoding='utf-8')
    assert response.text() == 'Hello, �'  # Should replace invalid byte

def test_text_with_large_content():
    response = MockResponse(b'A' * 10000, encoding='utf-8')
    assert response.text() == 'A' * 10000  # Should handle large content

