    with pytest.raises(RequestsSSLError):
        list(generator_instance.generate(1024))

def test_generate_with_read(mock_raw, generator_instance):
    mock_raw.read.side_effect = [b'chunk1', b'chunk2', b'']
    chunks = list(generator_instance.generate(1024))
    assert chunks == [b'chunk1', b'chunk2']

