import pytest
from arrow.util import is_timestamp, normalize_timestamp


MAX_TIMESTAMP = 2**31 - 1  # Example maximum timestamp for seconds
MAX_TIMESTAMP_MS = MAX_TIMESTAMP * 1000  # Maximum for milliseconds
MAX_TIMESTAMP_US = MAX_TIMESTAMP_MS * 1000  # Maximum for microseconds

def test_normalize_timestamp_seconds():
    assert normalize_timestamp(1000.0) == 1000.0

def test_normalize_timestamp_milliseconds():
    assert normalize_timestamp(1000000.0) == 1000.0

def test_normalize_timestamp_microseconds():
    assert normalize_timestamp(1000000000.0) == 1000.0

def test_normalize_timestamp_large_seconds():
    assert normalize_timestamp(MAX_TIMESTAMP + 1) == pytest.approx((MAX_TIMESTAMP + 1), rel=1e-9)

def test_normalize_timestamp_large_milliseconds():
    assert normalize_timestamp(MAX_TIMESTAMP_MS + 1) == pytest.approx((MAX_TIMESTAMP_MS + 1) / 1000, rel=1e-9)

def test_normalize_timestamp_large_microseconds():
    with pytest.raises(ValueError, match="The specified timestamp"):
        normalize_timestamp(MAX_TIMESTAMP_US + 1)

def test_normalize_timestamp_edge_case_max_seconds():
    assert normalize_timestamp(MAX_TIMESTAMP) == MAX_TIMESTAMP

def test_normalize_timestamp_edge_case_max_milliseconds():
    assert normalize_timestamp(MAX_TIMESTAMP_MS) == MAX_TIMESTAMP_MS / 1000

def test_normalize_timestamp_edge_case_max_microseconds():
    assert normalize_timestamp(MAX_TIMESTAMP_US) == MAX_TIMESTAMP_US / 1_000_000

