import pytest
from itertools import islice
from more_itertools import *
from more_itertools.more import *


def split_into(iterable, sizes):
    it = iter(iterable)
    for size in sizes:
        if size is None:
            yield list(it)
            return
        else:
            yield list(islice(it, size))

def test_split_into_normal_case():
    result = list(split_into([1, 2, 3, 4, 5, 6], [1, 2, 3]))
    assert result == [[1], [2, 3], [4, 5, 6]]

def test_split_into_smaller_sizes():
    result = list(split_into([1, 2, 3, 4, 5, 6], [2, 3]))
    assert result == [[1, 2], [3, 4, 5]]

def test_split_into_larger_sizes():
    result = list(split_into([1, 2, 3, 4], [1, 2, 3, 4]))
    assert result == [[1], [2, 3], [4], []]

def test_split_into_with_none():
    result = list(split_into([1, 2, 3, 4, 5, 6, 7, 8, 9, 0], [2, 3, None]))
    assert result == [[1, 2], [3, 4, 5], [6, 7, 8, 9, 0]]

def test_split_into_empty_iterable():
    result = list(split_into([], [1, 2, 3]))
    assert result == [[], [], []]

def test_split_into_empty_sizes():
    result = list(split_into([1, 2, 3, 4], []))
    assert result == []

def test_split_into_sizes_exceed_iterable():
    result = list(split_into([1, 2], [3, 4, 5]))
    assert result == [[1, 2], [], []]

def test_split_into_none_in_sizes_only():
    result = list(split_into([1, 2, 3], [None]))
    assert result == [[1, 2, 3]]

def test_split_into_sizes_with_zero():
    result = list(split_into([1, 2, 3, 4, 5], [0, 2, 3]))
    assert result == [[], [1, 2], [3, 4, 5]]

def test_split_into_large_iterable():
    result = list(split_into(range(100), [10, 20, 30, None]))
    assert result[0] == list(range(10))
    assert result[1] == list(range(10, 30))
    assert result[2] == list(range(30, 60))
    assert result[3] == list(range(60, 100))

def test_split_into_sizes_with_negative():
    result = list(split_into([1, 2, 3, 4], [-1, 2]))
    assert result == [[], [1, 2]]

