import pytest
from collections import deque
from itertools import repeat
import math
from more_itertools import *
from more_itertools.more import *


def circular_shifts(iterable, steps=1):
    buffer = deque(iterable)
    if steps == 0:
        raise ValueError('Steps should be a non-zero integer')

    buffer.rotate(steps)
    steps = -steps
    n = len(buffer)
    n //= math.gcd(n, steps)

    for _ in repeat(None, n):
        buffer.rotate(steps)
        yield tuple(buffer)

def test_circular_shifts_normal():
    assert list(circular_shifts(range(4))) == [(0, 1, 2, 3), (1, 2, 3, 0), (2, 3, 0, 1), (3, 0, 1, 2)]

def test_circular_shifts_with_steps():
    assert list(circular_shifts(range(4), 2)) == [(0, 1, 2, 3), (2, 3, 0, 1)]

def test_circular_shifts_negative_steps():
    assert list(circular_shifts(range(4), -1)) == [(0, 1, 2, 3), (3, 0, 1, 2), (2, 3, 0, 1), (1, 2, 3, 0)]

def test_circular_shifts_zero_steps():
    with pytest.raises(ValueError, match='Steps should be a non-zero integer'):
        list(circular_shifts(range(4), 0))

def test_circular_shifts_empty_iterable():
    assert list(circular_shifts([])) == []

def test_circular_shifts_single_element():
    assert list(circular_shifts([1])) == [(1,)]

def test_circular_shifts_multiple_steps():
    assert list(circular_shifts(range(5), 3)) == [(0, 1, 2, 3, 4), (3, 4, 0, 1, 2)]

def test_circular_shifts_large_steps():
    assert list(circular_shifts(range(4), 10)) == [(0, 1, 2, 3), (2, 3, 0, 1)]

def test_circular_shifts_negative_large_steps():
    assert list(circular_shifts(range(4), -10)) == [(0, 1, 2, 3), (1, 2, 3, 0)]

def test_circular_shifts_steps_greater_than_length():
    assert list(circular_shifts(range(3), 5)) == [(0, 1, 2), (1, 2, 0)]

def test_circular_shifts_steps_less_than_negative_length():
    assert list(circular_shifts(range(3), -5)) == [(0, 1, 2), (2, 0, 1)]

import pytest
from itertools import groupby
from operator import itemgetter
from more_itertools import *
from more_itertools.more import *


def consecutive_groups(iterable, ordering=None):
    if ordering is None:
        key = lambda x: x[0] - x[1]
    else:
        key = lambda x: x[0] - ordering(x[1])

    for k, g in groupby(enumerate(iterable), key=key):
        yield map(itemgetter(1), g)

def test_consecutive_groups_numbers():
    result = list(consecutive_groups([1, 10, 11, 12, 20, 30, 31, 32, 33, 40]))
    assert result == [[1], [10, 11, 12], [20], [30, 31, 32, 33], [40]]

def test_consecutive_groups_letters():
    result = list(consecutive_groups('abcdfgilmnop', ordering=ord))
    assert result == [['a', 'b', 'c', 'd'], ['f', 'g'], ['i'], ['l', 'm', 'n', 'o', 'p']]

def test_consecutive_groups_empty():
    result = list(consecutive_groups([]))
    assert result == []

def test_consecutive_groups_single_element():
    result = list(consecutive_groups([42]))
    assert result == [[42]]

def test_consecutive_groups_identical_elements():
    result = list(consecutive_groups([1, 1, 1, 1]))
    assert result == [[1, 1, 1, 1]]

def test_consecutive_groups_non_consecutive():
    result = list(consecutive_groups([1, 3, 5, 7, 9]))
    assert result == [[1], [3], [5], [7], [9]]

def test_consecutive_groups_with_custom_ordering():
    result = list(consecutive_groups(['a', 'b', 'c', 'e', 'f', 'g'], ordering=ord))
    assert result == [['a', 'b', 'c'], ['e', 'f', 'g']]

def test_consecutive_groups_with_mixed_types():
    result = list(consecutive_groups([1, 2, 'a', 'b', 3, 4], ordering=lambda x: x))
    assert result == [[1, 2], ['a', 'b'], [3, 4]]

def test_consecutive_groups_large_input():
    result = list(consecutive_groups(range(1000)))
    assert len(result) == 1
    assert result[0] == list(range(1000))

def test_consecutive_groups_with_non_adjacent_numbers():
    result = list(consecutive_groups([1, 2, 10, 11, 20, 21, 30]))
    assert result == [[1, 2], [10, 11], [20, 21], [30]]

def test_consecutive_groups_with_none_ordering():
    result = list(consecutive_groups([1, 2, 3, 5, 6, 7, 9]))
    assert result == [[1, 2, 3], [5, 6, 7], [9]]

