import pytest
from more_itertools import *
from more_itertools.more import *


class TestPeek:
    @pytest.fixture
    def iterator_with_items(self):
        return iter([1, 2, 3])

    @pytest.fixture
    def empty_iterator(self):
        return iter([])

    @pytest.fixture
    def custom_peek(self, iterator_with_items):
        class CustomPeek:
            def __init__(self, it):
                self._it = it
                self._cache = []

            def peek(self, default=_marker):
                if not self._cache:
                    try:
                        self._cache.append(next(self._it))
                    except StopIteration:
                        if default is _marker:
                            raise
                        return default
                return self._cache[0]

        return CustomPeek(iterator_with_items)

    def test_peek_next_item(self, custom_peek):
        assert custom_peek.peek() == 1

    def test_peek_multiple_calls(self, custom_peek):
        assert custom_peek.peek() == 1
        assert custom_peek.peek() == 1

    def test_peek_after_next(self, custom_peek):
        custom_peek.peek()  # Cache the first item
        next(custom_peek._it)  # Move to the next item
        assert custom_peek.peek() == 2

    def test_peek_empty_iterator_with_default(self, empty_iterator):
        custom_peek = CustomPeek(empty_iterator)
        assert custom_peek.peek(default='default_value') == 'default_value'

    def test_peek_empty_iterator_without_default(self, empty_iterator):
        custom_peek = CustomPeek(empty_iterator)
        with pytest.raises(StopIteration):
            custom_peek.peek()

    def test_peek_after_exhaustion(self, custom_peek):
        custom_peek.peek()  # Cache the first item
        next(custom_peek._it)  # Move to the next item
        next(custom_peek._it)  # Move to the last item
        next(custom_peek._it)  # Exhaust the iterator
        assert custom_peek.peek(default='default_value') == 'default_value'

