class TestIndex:
    @pytest.fixture
    def indexer(self):
        class Indexer:
            def __init__(self, start, stop, step):
                self._start = start
                self._stop = stop
                self._step = step
                self._zero = 0
                self._growing = True if step > 0 else False

            def index(self, value):
                if self._growing:
                    if self._start <= value < self._stop:
                        q, r = divmod(value - self._start, self._step)
                        if r == self._zero:
                            return int(q)
                else:
                    if self._start >= value > self._stop:
                        q, r = divmod(self._start - value, -self._step)
                        if r == self._zero:
                            return int(q)

                raise ValueError(f"{value} is not in numeric range")

        return Indexer

    def test_index_growing_within_range(self, indexer):
        idx = indexer(0, 10, 2)
        assert idx.index(2) == 1
        assert idx.index(4) == 2
        assert idx.index(6) == 3
        assert idx.index(8) == 4

    def test_index_growing_out_of_range(self, indexer):
        idx = indexer(0, 10, 2)
        with pytest.raises(ValueError):
            idx.index(10)
        with pytest.raises(ValueError):
            idx.index(-1)

    def test_index_growing_exact_start(self, indexer):
        idx = indexer(0, 10, 2)
        assert idx.index(0) == 0

    def test_index_growing_exact_stop(self, indexer):
        idx = indexer(0, 10, 2)
        with pytest.raises(ValueError):
            idx.index(10)

    def test_index_growing_non_multiple(self, indexer):
        idx = indexer(0, 10, 2)
        with pytest.raises(ValueError):
            idx.index(3)

    def test_index_decreasing_within_range(self, indexer):
        idx = indexer(10, 0, -2)
        assert idx.index(8) == 1
        assert idx.index(6) == 2
        assert idx.index(4) == 3
        assert idx.index(2) == 4

    def test_index_decreasing_out_of_range(self, indexer):
        idx = indexer(10, 0, -2)
        with pytest.raises(ValueError):
            idx.index(0)
        with pytest.raises(ValueError):
            idx.index(11)

    def test_index_decreasing_exact_start(self, indexer):
        idx = indexer(10, 0, -2)
        assert idx.index(10) == 0

    def test_index_decreasing_exact_stop(self, indexer):
        idx = indexer(10, 0, -2)
        with pytest.raises(ValueError):
            idx.index(0)

    def test_index_decreasing_non_multiple(self, indexer):
