@pytest.fixture
def url_builder():
    class URLBuilder:
        def __init__(self, url):
            self.url = url

        def path_url(self):
            url = []
            p = urlsplit(self.url)
            path = p.path
            if not path:
                path = "/"
            url.append(path)
            query = p.query
            if query:
                url.append("?")
                url.append(query)
            return "".join(url)

    return URLBuilder

def test_path_url_with_path(url_builder):
    builder = url_builder("http://example.com/path/to/resource")
    assert builder.path_url() == "/path/to/resource"

