import pytest
from requests.models import PreparedRequest, Request, Response
from requests.exceptions import HTTPError, JSONDecodeError
from requests.cookies import RequestsCookieJar
from requests.auth import HTTPBasicAuth


class TestDeregisterHook:
    @pytest.fixture
    def hook_manager(self):
        class HookManager:
            def __init__(self):
                self.hooks = {}

            def register_hook(self, event, hook):
                if event not in self.hooks:
                    self.hooks[event] = []
                self.hooks[event].append(hook)

            def deregister_hook(self, event, hook):
                """Deregister a previously registered hook.
                Returns True if the hook existed, False if not.
                """
                try:
                    self.hooks[event].remove(hook)
                    return True
                except ValueError:
                    return False

        return HookManager()

    def test_deregister_existing_hook(self, hook_manager):
        hook_manager.register_hook('event1', 'hook1')
        result = hook_manager.deregister_hook('event1', 'hook1')
        assert result is True
        assert 'hook1' not in hook_manager.hooks['event1']

    def test_deregister_non_existing_hook(self, hook_manager):
        hook_manager.register_hook('event1', 'hook1')
        result = hook_manager.deregister_hook('event1', 'hook2')
        assert result is False
        assert 'hook1' in hook_manager.hooks['event1']

    def test_deregister_hook_from_empty_event(self, hook_manager):
        result = hook_manager.deregister_hook('event1', 'hook1')
        assert result is False

    def test_deregister_hook_multiple_hooks(self, hook_manager):
        hook_manager.register_hook('event1', 'hook1')
        hook_manager.register_hook('event1', 'hook2')
        result = hook_manager.deregister_hook('event1', 'hook1')
        assert result is True
        assert 'hook1' not in hook_manager.hooks['event1']
        assert 'hook2' in hook_manager.hooks['event1']

    def test_deregister_hook_event_with_no_hooks(self, hook_manager):
        result = hook_manager.deregister_hook('event2', 'hook1')
        assert result is False

    def test_deregister_hook_event_with_none(self, hook_manager):
        hook_manager.register_hook('event1', None)
        result = hook_manager.deregister_hook('event1', None)
        assert result is True
        assert None not in hook_manager.hooks['event1']

import pytest
from collections import OrderedDict
from requests.utils import (address_in_network, dotted_netmask, is_ipv4_address, is_valid_cidr, requote_uri, unquote_unreserved, parse_list_header, parse_dict_header, unquote_header_value, parse_header_links, iter_slices, from_key_val_list, to_key_val_list, get_encoding_from_headers, resolve_proxies, urldefragauth, _validate_header_part)
from requests.exceptions import InvalidURL, InvalidHeader


def from_key_val_list(value):
    if value is None:
        return None

    if isinstance(value, (str, bytes, bool, int)):
        raise ValueError("cannot encode objects that are not 2-tuples")

    return OrderedDict(value)

def test_from_key_val_list_with_ordered_dict():
    result = from_key_val_list(OrderedDict([('key', 'val')]))
    assert result == OrderedDict([('key', 'val')])

def test_from_key_val_list_with_list_of_tuples():
    result = from_key_val_list([('key1', 'val1'), ('key2', 'val2')])
    assert result == OrderedDict([('key1', 'val1'), ('key2', 'val2')])

def test_from_key_val_list_with_dict():
    result = from_key_val_list({'key': 'val'})
    assert result == OrderedDict([('key', 'val')])

def test_from_key_val_list_with_empty_list():
    result = from_key_val_list([])
    assert result == OrderedDict()

def test_from_key_val_list_with_none():
    result = from_key_val_list(None)
    assert result is None

def test_from_key_val_list_with_string():
    with pytest.raises(ValueError, match="cannot encode objects that are not 2-tuples"):
        from_key_val_list("string")

def test_from_key_val_list_with_integer():
    with pytest.raises(ValueError, match="cannot encode objects that are not 2-tuples"):
        from_key_val_list(123)

def test_from_key_val_list_with_boolean():
    with pytest.raises(ValueError, match="cannot encode objects that are not 2-tuples"):
        from_key_val_list(True)

def test_from_key_val_list_with_bytes():
    with pytest.raises(ValueError, match="cannot encode objects that are not 2-tuples"):
        from_key_val_list(b'bytes')

def test_from_key_val_list_with_invalid_tuple():
    with pytest.raises(ValueError, match="cannot encode objects that are not 2-tuples"):
        from_key_val_list([('key1',)])

def test_from_key_val_list_with_nested_tuples():
    result = from_key_val_list([('key1', ('nested_key', 'nested_val'))])
    assert result == OrderedDict([('key1', ('nested_key', 'nested_val'))])

