class MockRequest:
    def __init__(self, method):
        self.method = method
        self.headers = {}

    def prepare_content_length(self, body):
        if body is not None:
            length = super_len(body)
            if length:
                self.headers["Content-Length"] = builtin_str(length)
        elif (
            self.method not in ("GET", "HEAD")
            and self.headers.get("Content-Length") is None
        ):
            self.headers["Content-Length"] = "0"

def super_len(body):
    return len(body)

def builtin_str(value):
    return str(value)

@pytest.fixture
def mock_request():
    return MockRequest("POST")

def test_prepare_content_length_with_body(mock_request):
    mock_request.prepare_content_length("test body")
    assert mock_request.headers["Content-Length"] == "9"

