    assert mock_request.headers["Content-Length"] == "0"

def test_prepare_content_length_with_none_body(mock_request):
    mock_request.prepare_content_length(None)
    assert "Content-Length" not in mock_request.headers

def test_prepare_content_length_get_method(mock_request):
