import pytest
from unittest.mock import Mock
from requests.models import PreparedRequest, Request, Response
from requests.exceptions import HTTPError, JSONDecodeError
from requests.cookies import RequestsCookieJar
from requests.auth import HTTPBasicAuth


class TestRegisterHook:
    @pytest.fixture
    def hook_manager(self):
        class HookManager:
            def __init__(self):
                self.hooks = {
                    'event1': [],
                    'event2': []
                }

            def register_hook(self, event, hook):
                if event not in self.hooks:
                    raise ValueError(f'Unsupported event specified, with event name "{event}"')

                if isinstance(hook, Callable):
                    self.hooks[event].append(hook)
                elif hasattr(hook, "__iter__"):
                    self.hooks[event].extend(h for h in hook if isinstance(h, Callable))

        return HookManager()

    def test_register_single_callable_hook(self, hook_manager):
        hook = Mock()
        hook_manager.register_hook('event1', hook)
        assert hook_manager.hooks['event1'] == [hook]

    def test_register_multiple_callable_hooks(self, hook_manager):
        hook1 = Mock()
        hook2 = Mock()
        hook_manager.register_hook('event1', [hook1, hook2])
        assert hook_manager.hooks['event1'] == [hook1, hook2]

    def test_register_iterable_with_non_callable(self, hook_manager):
        hook1 = Mock()
        hook2 = "not_a_callable"
        hook_manager.register_hook('event1', [hook1, hook2])
        assert hook_manager.hooks['event1'] == [hook1]

    def test_register_hook_to_nonexistent_event(self, hook_manager):
        with pytest.raises(ValueError, match='Unsupported event specified'):
            hook_manager.register_hook('event3', Mock())

    def test_register_hook_to_empty_event(self, hook_manager):
        with pytest.raises(ValueError, match='Unsupported event specified'):
            hook_manager.register_hook('', Mock())

    def test_register_hook_with_none(self, hook_manager):
        hook_manager.register_hook('event1', None)
        assert hook_manager.hooks['event1'] == []

    def test_register_hook_with_empty_iterable(self, hook_manager):
        hook_manager.register_hook('event1', [])
        assert hook_manager.hooks['event1'] == []

import pytest
from requests.exceptions import HTTPError
from requests.models import PreparedRequest, Request, Response
from requests.exceptions import HTTPError, JSONDecodeError
from requests.cookies import RequestsCookieJar
from requests.auth import HTTPBasicAuth


class MockResponse:
    def __init__(self, status_code, reason, url):
        self.status_code = status_code
        self.reason = reason
        self.url = url

    def raise_for_status(self):
        # The function to be tested
        http_error_msg = ""
        if isinstance(self.reason, bytes):
            try:
                reason = self.reason.decode("utf-8")
            except UnicodeDecodeError:
                reason = self.reason.decode("iso-8859-1")
        else:
            reason = self.reason

        if 400 <= self.status_code < 500:
            http_error_msg = (
                f"{self.status_code} Client Error: {reason} for url: {self.url}"
            )

        elif 500 <= self.status_code < 600:
            http_error_msg = (
                f"{self.status_code} Server Error: {reason} for url: {self.url}"
            )

        if http_error_msg:
            raise HTTPError(http_error_msg, response=self)

def test_raise_for_status_client_error():
    response = MockResponse(404, "Not Found", "http://example.com")
    with pytest.raises(HTTPError) as excinfo:
        response.raise_for_status()
    assert str(excinfo.value) == "404 Client Error: Not Found for url: http://example.com"

def test_raise_for_status_server_error():
    response = MockResponse(500, "Internal Server Error", "http://example.com")
    with pytest.raises(HTTPError) as excinfo:
        response.raise_for_status()
    assert str(excinfo.value) == "500 Server Error: Internal Server Error for url: http://example.com"

def test_raise_for_status_bytes_reason_utf8():
    response = MockResponse(400, b"Bad Request", "http://example.com")
    with pytest.raises(HTTPError) as excinfo:
        response.raise_for_status()
    assert str(excinfo.value) == "400 Client Error: Bad Request for url: http://example.com"

def test_raise_for_status_bytes_reason_iso88591():
    response = MockResponse(400, b"\xC3\xA9", "http://example.com")  # é in bytes
