class TestFrameClass:
    _ATTRS = ["year", "month", "day", "hour", "minute", "second", "microsecond"]

    def _get_frames(cls, name: str) -> Tuple[str, str, int]:
        if name in cls._ATTRS:
            return name, f"{name}s", 1
        elif name[-1] == "s" and name[:-1] in cls._ATTRS:
            return name[:-1], name, 1
        elif name in ["week", "weeks"]:
            return "week", "weeks", 1
        elif name in ["quarter", "quarters"]:
            return "quarter", "months", 3
        else:
            supported = ", ".join(
                [
                    "year(s)",
                    "month(s)",
                    "day(s)",
                    "hour(s)",
                    "minute(s)",
                    "second(s)",
                    "microsecond(s)",
                    "week(s)",
                    "quarter(s)",
                ]
            )
            raise ValueError(
                f"Range or span over frame {name} not supported. Supported frames: {supported}."
            )

@pytest.fixture
def frame_class():
    return TestFrameClass

def test_get_frames_valid_single(frame_class):
    assert frame_class._get_frames("day") == ("day", "days", 1)

def test_get_frames_valid_plural(frame_class):
    assert frame_class._get_frames("days") == ("day", "days", 1)

