    assert frame_class._get_frames("quarters") == ("quarter", "months", 3)

def test_get_frames_invalid(frame_class):
    with pytest.raises(ValueError) as excinfo:
        frame_class._get_frames("invalid")
    assert "not supported" in str(excinfo.value)

def test_get_frames_invalid_empty(frame_class):
    with pytest.raises(ValueError) as excinfo:
        frame_class._get_frames("")
    assert "not supported" in str(excinfo.value)

def test_get_frames_invalid_numeric(frame_class):
    with pytest.raises(ValueError) as excinfo:
        frame_class._get_frames("123")
