class MockFormatter:
    def __init__(self):
        self.timeframes = {
            "days": {
                "zero": "0 days",
                "past": "{} days ago",
                "future": "in {} days",
                "future-singular": "in {} day",
                "future-paucal": "in {} days",
            },
            "hours": {
                "zero": "0 hours",
                "past": "{} hours ago",
                "future": "in {} hours",
                "future-singular": "in {} hour",
                "future-paucal": "in {} hours",
            },
        }

    def _format_timeframe(self, timeframe: str, delta: int) -> str:
        abs_delta = abs(delta)
        form = self.timeframes[timeframe]

        if isinstance(form, str):
            return form.format(abs_delta)

        if delta == 0:
            key = "zero"
        elif delta < 0:
            key = "past"
        else:
            if "future-singular" not in form:
                key = "future"
            elif 2 <= abs_delta % 10 <= 4 and (
                abs_delta % 100 < 10 or abs_delta % 100 >= 20
            ):
                key = "future-singular"
            else:
                key = "future-paucal"

        form: str = form[key]
        return form.format(abs_delta)

@pytest.fixture
def formatter():
    return MockFormatter()

def test_format_timeframe_zero_days(formatter):
    assert formatter._format_timeframe("days", 0) == "0 days"

def test_format_timeframe_past_days(formatter):
