import pytest
from itertools import tee
from more_itertools import *
from more_itertools.recipes import *


def triplewise(iterable):
    t1, t2, t3 = tee(iterable, 3)
    next(t3, None)
    next(t3, None)
    next(t2, None)
    return zip(t1, t2, t3)

def test_triplewise_normal_case():
    result = list(triplewise('ABCDE'))
    assert result == [('A', 'B', 'C'), ('B', 'C', 'D'), ('C', 'D', 'E')]

def test_triplewise_empty_iterable():
    result = list(triplewise([]))
    assert result == []

def test_triplewise_single_element():
    result = list(triplewise(['A']))
    assert result == []

def test_triplewise_two_elements():
    result = list(triplewise(['A', 'B']))
    assert result == []

def test_triplewise_three_elements():
    result = list(triplewise(['A', 'B', 'C']))
    assert result == [('A', 'B', 'C')]

def test_triplewise_with_numbers():
    result = list(triplewise([1, 2, 3, 4]))
    assert result == [(1, 2, 3), (2, 3, 4)]

def test_triplewise_with_mixed_types():
    result = list(triplewise(['A', 1, 'B', 2, 'C']))
    assert result == [('A', 1, 'B'), (1, 'B', 2), ('B', 2, 'C')]

def test_triplewise_with_generator():
    def gen():
        yield from range(5)
    result = list(triplewise(gen()))
    assert result == [(0, 1, 2), (1, 2, 3), (2, 3, 4)]

def test_triplewise_with_large_iterable():
    result = list(triplewise(range(100)))
    assert result == [(i, i + 1, i + 2) for i in range(98)]

def test_triplewise_with_non_iterable():
    with pytest.raises(TypeError):
        list(triplewise(123))

import pytest
from itertools import islice
from more_itertools import *
from more_itertools.more import *


def split_into(iterable, sizes):
    it = iter(iterable)
    for size in sizes:
        if size is None:
            yield list(it)
            return
        else:
            yield list(islice(it, size))

def test_split_into_normal_case():
    result = list(split_into([1, 2, 3, 4, 5, 6], [1, 2, 3]))
    assert result == [[1], [2, 3], [4, 5, 6]]

def test_split_into_remaining_items_not_returned():
    result = list(split_into([1, 2, 3, 4, 5, 6], [2, 3]))
    assert result == [[1, 2], [3, 4, 5]]

def test_split_into_overrun_sizes():
    result = list(split_into([1, 2, 3, 4], [1, 2, 3, 4]))
    assert result == [[1], [2, 3], [4], []]

def test_split_into_none_in_sizes():
    result = list(split_into([1, 2, 3, 4, 5, 6, 7, 8, 9, 0], [2, 3, None]))
    assert result == [[1, 2], [3, 4, 5], [6, 7, 8, 9, 0]]

def test_split_into_empty_iterable():
    result = list(split_into([], [1, 2, 3]))
