class TestPeek:
    @pytest.fixture
    def iterator(self):
        return iter([1, 2, 3])

    @pytest.fixture
    def peekable(self, iterator):
        class Peekable:
            def __init__(self, it):
                self._it = it
                self._cache = []

            def peek(self, default=_marker):
                if not self._cache:
                    try:
                        self._cache.append(next(self._it))
                    except StopIteration:
                        if default is _marker:
                            raise
                        return default
                return self._cache[0]

        return Peekable(iterator)

    def test_peek_next_item(self, peekable):
        assert peekable.peek() == 1

    def test_peek_multiple_calls(self, peekable):
        assert peekable.peek() == 1
        assert peekable.peek() == 1

    def test_peek_after_next(self, peekable):
        peekable.peek()
        next(peekable._it)
        assert peekable.peek() == 2

    def test_peek_empty_iterator(self):
        class EmptyPeekable:
            def __init__(self):
                self._it = iter([])
                self._cache = []

            def peek(self, default=_marker):
                if not self._cache:
                    try:
                        self._cache.append(next(self._it))
                    except StopIteration:
                        if default is _marker:
                            raise
                        return default
                return self._cache[0]

        empty_peekable = EmptyPeekable()
        with pytest.raises(StopIteration):
            empty_peekable.peek()

    def test_peek_with_default(self):
        class SingleItemPeekable:
            def __init__(self):
                self._it = iter([42])
                self._cache = []

            def peek(self, default=_marker):
                if not self._cache:
                    try:
                        self._cache.append(next(self._it))
                    except StopIteration:
                        if default is _marker:
