        next(single_item_peekable._it)
        assert single_item_peekable.peek(default="default") == "default"

    def test_peek_empty_with_default(self):
        class EmptyPeekable:
            def __init__(self):
                self._it = iter([])
                self._cache = []

            def peek(self, default=_marker):
