def test_parse_header_links_normal_cases():
    assert parse_header_links('<http://example.com/front.jpeg>; rel=front; type="image/jpeg", <http://example.com/back.jpeg>; rel=back; type="image/jpeg"') == [
        {'url': 'http://example.com/front.jpeg', 'rel': 'front', 'type': 'image/jpeg'},
        {'url': 'http://example.com/back.jpeg', 'rel': 'back', 'type': 'image/jpeg'}
    ]

    assert parse_header_links('<http://example.com/image.png>; rel=image') == [
        {'url': 'http://example.com/image.png', 'rel': 'image'}
    ]

    assert parse_header_links('<http://example.com/doc.pdf>; rel=document; type="application/pdf", <http://example.com/image.jpg>; rel=image; type="image/jpeg"') == [
        {'url': 'http://example.com/doc.pdf', 'rel': 'document', 'type': 'application/pdf'},
        {'url': 'http://example.com/image.jpg', 'rel': 'image', 'type': 'image/jpeg'}
    ]

def test_parse_header_links_edge_cases():
    assert parse_header_links('') == []
    assert parse_header_links('   ') == []
    assert parse_header_links('<http://example.com/>') == [{'url': 'http://example.com/'}]
    assert parse_header_links('<http://example.com/>;') == [{'url': 'http://example.com/'}]
    assert parse_header_links('<http://example.com/>; rel=') == [{'url': 'http://example.com/', 'rel': ''}]
    assert parse_header_links('<http://example.com/>; rel=front; type=') == [{'url': 'http://example.com/', 'rel': 'front', 'type': ''}]
    assert parse_header_links('<http://example.com/>; rel=front; type="image/jpeg";;') == [{'url': 'http://example.com/', 'rel': 'front', 'type': 'image/jpeg'}]

