# Assuming the class containing describe_multi is named TimeframeDescriber
# and has a method _format_timeframe and _format_relative.

class MockTimeframeDescriber:
    def __init__(self, and_word=None):
        self.and_word = and_word

    def _format_timeframe(self, timeframe: str, delta: Union[int, float]) -> str:
        return f"{delta} {timeframe}"

    def _format_relative(self, humanized: str, unit: str, value: int) -> str:
        return f"{humanized} ago" if value > 0 else f"{humanized} in the future"

    def describe_multi(self, timeframes: Sequence[Tuple[str, Union[int, float]]], only_distance: bool = False) -> str:
        parts = [
            self._format_timeframe(timeframe, int(delta))
            for timeframe, delta in timeframes
        ]
        if self.and_word:
            parts.insert(-1, self.and_word)
        humanized = " ".join(parts)

        if not only_distance:
            timeframe_value = 0
            for _, unit_value in timeframes:
                if int(unit_value) != 0:
                    timeframe_value = int(unit_value)
                    break
            humanized = self._format_relative(humanized, "seconds", timeframe_value)

        return humanized


@pytest.fixture
def describer():
    return MockTimeframeDescriber()

def test_describe_multi_normal_cases(describer):
    assert describer.describe_multi([("hours", 2), ("minutes", 30)]) == "2 hours 30 minutes ago"
    assert describer.describe_multi([("days", 1), ("hours", 5)]) == "1 days 5 hours ago"
    assert describer.describe_multi([("seconds", 45), ("minutes", 1)]) == "45 seconds 1 minutes ago"

