    assert describer.describe_multi([("seconds", 0), ("minutes", 0)], only_distance=True) == "0 seconds 0 minutes"
    assert describer.describe_multi([("days", 0), ("hours", 0)], only_distance=True) == "0 days 0 hours"

def test_describe_multi_with_and_word(describer):
    describer.and_word = "and"
    assert describer.describe_multi([("hours", 2), ("minutes", 30)]) == "2 hours and 30 minutes ago"
    assert describer.describe_multi([("days", 1), ("hours", 5)]) == "1 days and 5 hours ago"

def test_describe_multi_with_negative_values(describer):
