import pytest
from arrow.util import is_timestamp, normalize_timestamp


MAX_TIMESTAMP = 1_000_000_000_000  # Example value for max timestamp in seconds
MAX_TIMESTAMP_MS = 1_000_000_000  # Example value for max timestamp in milliseconds
MAX_TIMESTAMP_US = 1_000_000  # Example value for max timestamp in microseconds

def normalize_timestamp(timestamp: float) -> float:
    """Normalize millisecond and microsecond timestamps into normal timestamps."""
    if timestamp > MAX_TIMESTAMP:
        if timestamp < MAX_TIMESTAMP_MS:
            timestamp /= 1000
        elif timestamp < MAX_TIMESTAMP_US:
            timestamp /= 1_000_000
        else:
            raise ValueError(f"The specified timestamp {timestamp!r} is too large.")
    return timestamp

def test_normalize_timestamp_seconds():
    assert normalize_timestamp(1_000_000_000) == 1_000_000_000
    assert normalize_timestamp(500_000_000) == 500_000_000

def test_normalize_timestamp_milliseconds():
    assert normalize_timestamp(1_000_000_000_000) == 1_000_000_000  # 1 billion milliseconds = 1 million seconds
    assert normalize_timestamp(1_500_000_000_000) == 1_500_000_000  # 1.5 billion milliseconds = 1.5 million seconds

def test_normalize_timestamp_microseconds():
    assert normalize_timestamp(1_000_000_000_000_000) == 1_000_000_000  # 1 trillion microseconds = 1 million seconds
    assert normalize_timestamp(1_500_000_000_000_000) == 1_500_000_000  # 1.5 trillion microseconds = 1.5 million seconds

def test_edge_case_max_timestamp():
    assert normalize_timestamp(MAX_TIMESTAMP) == MAX_TIMESTAMP

def test_edge_case_max_timestamp_ms():
    assert normalize_timestamp(MAX_TIMESTAMP_MS) == MAX_TIMESTAMP_MS

def test_edge_case_max_timestamp_us():
    assert normalize_timestamp(MAX_TIMESTAMP_US) == MAX_TIMESTAMP_US

def test_too_large_timestamp():
    with pytest.raises(ValueError, match="The specified timestamp 10000000000000000 is too large."):
        normalize_timestamp(10_000_000_000_000_000)

def test_negative_timestamp():
    assert normalize_timestamp(-1) == -1
    assert normalize_timestamp(-1_000) == -1_000

def test_zero_timestamp():
    assert normalize_timestamp(0) == 0

def test_small_timestamp():
    assert normalize_timestamp(0.5) == 0.5  # Normal case
    assert normalize_timestamp(0.0005) == 0.0005  # Small timestamp in seconds

