import pytest
from more_itertools import *
from more_itertools.more import *


class TestPeek:
    class MockIterator:
        def __init__(self, items):
            self.items = items
            self.index = 0

        def __iter__(self):
            return self

        def __next__(self):
            if self.index < len(self.items):
                item = self.items[self.index]
                self.index += 1
                return item
            raise StopIteration

    class Peekable:
        _marker = object()

        def __init__(self, iterable):
            self._it = iter(iterable)
            self._cache = []

        def peek(self, default=_marker):
            if not self._cache:
                try:
                    self._cache.append(next(self._it))
                except StopIteration:
                    if default is self._marker:
                        raise
                    return default
            return self._cache[0]

    def test_peek_next_item(self):
        peekable = self.Peekable([1, 2, 3])
        assert peekable.peek() == 1

    def test_peek_multiple_calls(self):
        peekable = self.Peekable([1, 2, 3])
        assert peekable.peek() == 1
        assert peekable.peek() == 1

    def test_peek_after_next(self):
        peekable = self.Peekable([1, 2, 3])
        assert peekable.peek() == 1
        next(peekable._it)
        assert peekable.peek() == 2

    def test_peek_empty_iterator_with_default(self):
        peekable = self.Peekable([])
        assert peekable.peek(default='default_value') == 'default_value'

    def test_peek_empty_iterator_without_default(self):
        peekable = self.Peekable([])
        with pytest.raises(StopIteration):
            peekable.peek()

    def test_peek_after_exhaustion(self):
        peekable = self.Peekable([1])
        assert peekable.peek() == 1
        next(peekable._it)
        assert peekable.peek(default='default_value') == 'default_value'

    def test_peek_with_multiple_exhaustions(self):
        peekable = self.Peekable([1, 2])
        assert peekable.peek() == 1
        next(peekable._it)
        assert peekable.peek() == 2
        next(peekable._it)
        assert peekable.peek(default='default_value') == 'default_value'

    def test_peek_with_custom_marker(self):
        custom_marker = object()
        peekable = self.Peekable([])
        with pytest.raises(StopIteration):
            peekable.peek(custom_marker)

    def test_peek_with_non_iterable(self):
        with pytest.raises(TypeError):
            self.Peekable(None)

    def test_peek_with_empty_iterable(self):
        peekable = self.Peekable([])
        assert peekable.peek(default='default_value') == 'default_value'

import pytest
from itertools import cycle, count, islice
from more_itertools import *
from more_itertools.more import *


def count_cycle(iterable, n=None):
    """Cycle through the items from *iterable* up to *n* times, yielding
    the number of completed cycles along with each item. If *n* is omitted the
    process repeats indefinitely.

    >>> list(count_cycle('AB', 3))
    [(0, 'A'), (0, 'B'), (1, 'A'), (1, 'B'), (2, 'A'), (2, 'B')]
    """
    if n is not None:
        return product(range(n), iterable)
    seq = tuple(iterable)
    if not seq:
        return iter(())
    counter = count() if n is None else range(n)
    return zip(repeat_each(counter, len(seq)), cycle(seq))


def repeat_each(counter, length):
    for count in counter:
        for _ in range(length):
            yield count


@pytest.mark.parametrize("iterable, n, expected", [
    ('AB', 3, [(0, 'A'), (0, 'B'), (1, 'A'), (1, 'B'), (2, 'A'), (2, 'B')]),
    ([1, 2], 2, [(0, 1), (0, 2), (1, 1), (1, 2)]),
    (['x', 'y', 'z'], 1, [(0, 'x'), (0, 'y'), (0, 'z')]),
])
def test_count_cycle_normal_cases(iterable, n, expected):
    assert list(count_cycle(iterable, n)) == expected


def test_count_cycle_infinite():
    result = list(islice(count_cycle('AB'), 6))
    expected = [(0, 'A'), (0, 'B'), (1, 'A'), (1, 'B'), (2, 'A'), (2, 'B')]
    assert result == expected


def test_count_cycle_empty_iterable():
    assert list(count_cycle([], 3)) == []


def test_count_cycle_empty_iterable_infinite():
    assert list(count_cycle([], None)) == []


@pytest.mark.parametrize("iterable, n", [
    (None, 3),
    (5, 3),
    (object, 3),
])
def test_count_cycle_invalid_iterable(iterable, n):
    with pytest.raises(TypeError):
        list(count_cycle(iterable, n))


def test_count_cycle_no_n():
    result = list(count_cycle('ABC'))
    expected = [(0, 'A'), (0, 'B'), (0, 'C'), (1, 'A'), (1, 'B'), (1, 'C')]
    assert result[:6] == expected


def test_count_cycle_large_n():
    result = list(count_cycle('A', 1000))
    expected = [(i, 'A') for i in range(1000)]
    assert result == expected

