import pytest
from arrow.util import is_timestamp, normalize_timestamp


MAX_TIMESTAMP = 1_000_000_000_000  # Example value for max timestamp in seconds
MAX_TIMESTAMP_MS = 1_000_000_000  # Example value for max timestamp in milliseconds
MAX_TIMESTAMP_US = 1_000_000  # Example value for max timestamp in microseconds

def normalize_timestamp(timestamp: float) -> float:
    """Normalize millisecond and microsecond timestamps into normal timestamps."""
    if timestamp > MAX_TIMESTAMP:
        if timestamp < MAX_TIMESTAMP_MS:
            timestamp /= 1000
        elif timestamp < MAX_TIMESTAMP_US:
            timestamp /= 1_000_000
        else:
            raise ValueError(f"The specified timestamp {timestamp!r} is too large.")
    return timestamp

def test_normalize_timestamp_seconds():
    assert normalize_timestamp(1_000_000_000) == 1_000_000_000
    assert normalize_timestamp(500_000_000) == 500_000_000

def test_normalize_timestamp_milliseconds():
    assert normalize_timestamp(1_000_000_000_000) == 1_000_000_000  # 1 second in milliseconds
    assert normalize_timestamp(1_500_000_000_000) == 1_500_000_000  # 1.5 seconds in milliseconds

def test_normalize_timestamp_microseconds():
    assert normalize_timestamp(1_000_000_000_000_000) == 1_000_000_000  # 1 second in microseconds
    assert normalize_timestamp(1_500_000_000_000_000) == 1_500_000_000  # 1.5 seconds in microseconds

def test_edge_case_max_timestamp():
    assert normalize_timestamp(MAX_TIMESTAMP) == MAX_TIMESTAMP
    assert normalize_timestamp(MAX_TIMESTAMP_MS) == MAX_TIMESTAMP_MS
    assert normalize_timestamp(MAX_TIMESTAMP_US) == MAX_TIMESTAMP_US

def test_edge_case_below_max():
    assert normalize_timestamp(MAX_TIMESTAMP - 1) == MAX_TIMESTAMP - 1
    assert normalize_timestamp(MAX_TIMESTAMP_MS - 1) == MAX_TIMESTAMP_MS - 1
    assert normalize_timestamp(MAX_TIMESTAMP_US - 1) == MAX_TIMESTAMP_US - 1

def test_error_condition_too_large():
    with pytest.raises(ValueError, match="The specified timestamp"):
        normalize_timestamp(1_000_000_000_000_001)  # Just above max timestamp
    with pytest.raises(ValueError, match="The specified timestamp"):
        normalize_timestamp(1_000_000_000_000_000)  # Just above max milliseconds
    with pytest.raises(ValueError, match="The specified timestamp"):
        normalize_timestamp(1_000_000_000_000_000_000)  # Just above max microseconds

def test_normal_case_zero():
    assert normalize_timestamp(0) == 0

def test_normal_case_negative():
    assert normalize_timestamp(-1) == -1  # Negative timestamp should remain unchanged

