class TestFormatTimeframe:
    @pytest.fixture
    def setup(self):
        class TimeFrameFormatter:
            timeframes = {
                'days': {
                    'zero': "0 days",
                    'past': "{} days ago",
                    'future': "in {} days",
                    'future-singular': "in {} day",
                    'future-paucal': "in {} days",
                }
            }

            def _format_timeframe(self, timeframe, delta):
                abs_delta = abs(delta)
                form = self.timeframes[timeframe]

                if isinstance(form, str):
                    return form.format(abs_delta)

                if delta == 0:
                    key = "zero"
                elif delta < 0:
                    key = "past"
                else:
                    if "future-singular" not in form:
                        key = "future"
                    elif 2 <= abs_delta % 10 <= 4 and (
                        abs_delta % 100 < 10 or abs_delta % 100 >= 20
                    ):
                        key = "future-singular"
                    else:
                        key = "future-paucal"

                form: str = form[key]
                return form.format(abs_delta)

        return TimeFrameFormatter()

