from arrow.util import is_timestamp, normalize_timestamp


MAX_TIMESTAMP = 1_000_000_000  # Example value for max timestamp
MAX_TIMESTAMP_MS = 1_000_000_000_000  # Example value for max timestamp in milliseconds
MAX_TIMESTAMP_US = 1_000_000_000_000_000  # Example value for max timestamp in microseconds

def normalize_timestamp(timestamp: float) -> float:
    """Normalize millisecond and microsecond timestamps into normal timestamps."""
    if timestamp > MAX_TIMESTAMP:
        if timestamp < MAX_TIMESTAMP_MS:
            timestamp /= 1000
        elif timestamp < MAX_TIMESTAMP_US:
            timestamp /= 1_000_000
        else:
            raise ValueError(f"The specified timestamp {timestamp!r} is too large.")
    return timestamp

def test_normalize_timestamp_seconds():
    assert normalize_timestamp(500) == 500
    assert normalize_timestamp(999999999) == 999999999

def test_normalize_timestamp_milliseconds():
    assert normalize_timestamp(1_000_000_000) == 1_000_000  # 1 second
    assert normalize_timestamp(1_500_000_000) == 1_500_000  # 1.5 seconds
    assert normalize_timestamp(1_999_999_999) == 1_999_999.999  # Just below 2 seconds

def test_normalize_timestamp_microseconds():
    assert normalize_timestamp(1_000_000_000_000) == 1_000_000  # 1 second
    assert normalize_timestamp(1_500_000_000_000) == 1_500_000  # 1.5 seconds
    assert normalize_timestamp(1_999_999_999_999) == 1_999_999.999999  # Just below 2 seconds

def test_normalize_timestamp_too_large():
    with pytest.raises(ValueError, match="The specified timestamp"):
        normalize_timestamp(1_000_000_000_000_000)  # Exceeds max timestamp in microseconds

def test_normalize_timestamp_edge_cases():
    assert normalize_timestamp(MAX_TIMESTAMP) == MAX_TIMESTAMP  # Edge case at max timestamp
    assert normalize_timestamp(MAX_TIMESTAMP_MS - 1) == (MAX_TIMESTAMP_MS - 1) / 1000  # Just below max ms
    assert normalize_timestamp(MAX_TIMESTAMP_US - 1) == (MAX_TIMESTAMP_US - 1) / 1_000_000  # Just below max us

def test_normalize_timestamp_zero():
    assert normalize_timestamp(0) == 0  # Zero timestamp

def test_normalize_timestamp_negative():
    assert normalize_timestamp(-1) == -1  # Negative timestamp should remain unchanged

