import pytest
from unittest.mock import Mock
from requests.models import PreparedRequest, Request, Response
from requests.exceptions import HTTPError, JSONDecodeError
from requests.cookies import RequestsCookieJar
from requests.auth import HTTPBasicAuth


class HTTPError(Exception):
    pass

class Response:
    def __init__(self, status_code, reason, url):
        self.status_code = status_code
        self.reason = reason
        self.url = url

    def raise_for_status(self):
        http_error_msg = ""
        if isinstance(self.reason, bytes):
            try:
                reason = self.reason.decode("utf-8")
            except UnicodeDecodeError:
                reason = self.reason.decode("iso-8859-1")
        else:
            reason = self.reason

        if 400 <= self.status_code < 500:
            http_error_msg = (
                f"{self.status_code} Client Error: {reason} for url: {self.url}"
            )

        elif 500 <= self.status_code < 600:
            http_error_msg = (
                f"{self.status_code} Server Error: {reason} for url: {self.url}"
            )

        if http_error_msg:
            raise HTTPError(http_error_msg, response=self)

def test_raise_for_status_client_error():
    response = Response(404, "Not Found", "http://example.com")
    with pytest.raises(HTTPError) as excinfo:
        response.raise_for_status()
    assert str(excinfo.value) == "404 Client Error: Not Found for url: http://example.com"

def test_raise_for_status_server_error():
    response = Response(500, "Internal Server Error", "http://example.com")
    with pytest.raises(HTTPError) as excinfo:
        response.raise_for_status()
    assert str(excinfo.value) == "500 Server Error: Internal Server Error for url: http://example.com"

def test_raise_for_status_bytes_utf8():
    response = Response(404, b"Not Found", "http://example.com")
    with pytest.raises(HTTPError) as excinfo:
        response.raise_for_status()
    assert str(excinfo.value) == "404 Client Error: Not Found for url: http://example.com"

def test_raise_for_status_bytes_iso88591():
    response = Response(404, b"\xe9", "http://example.com")  # 'é' in iso-8859-1
    with pytest.raises(HTTPError) as excinfo:
        response.raise_for_status()
    assert str(excinfo.value) == "404 Client Error: é for url: http://example.com"

def test_raise_for_status_no_error():
    response = Response(200, "OK", "http://example.com")
    try:
        response.raise_for_status()
    except HTTPError:
        pytest.fail("HTTPError was raised unexpectedly!")

def test_raise_for_status_empty_reason():
    response = Response(404, "", "http://example.com")
    with pytest.raises(HTTPError) as excinfo:
        response.raise_for_status()
    assert str(excinfo.value) == "404 Client Error:  for url: http://example.com"

def test_raise_for_status_non_bytes_reason():
    response = Response(400, None, "http://example.com")
    with pytest.raises(HTTPError) as excinfo:
        response.raise_for_status()
    assert str(excinfo.value) == "400 Client Error: None for url: http://example.com"

def test_raise_for_status_invalid_utf8():
    response = Response(400, b'\x80\x81\x82', "http://example.com")  # Invalid UTF-8
    with pytest.raises(HTTPError) as excinfo:
        response.raise_for_status()
    assert str(excinfo.value) == "400 Client Error: \x82 for url: http://example.com"

