import pytest
from itertools import cycle, count, islice
from more_itertools import *
from more_itertools.more import *


def count_cycle(iterable, n=None):
    """Cycle through the items from *iterable* up to *n* times, yielding
    the number of completed cycles along with each item. If *n* is omitted the
    process repeats indefinitely.

    >>> list(count_cycle('AB', 3))
    [(0, 'A'), (0, 'B'), (1, 'A'), (1, 'B'), (2, 'A'), (2, 'B')]
    """
    if n is not None:
        return product(range(n), iterable)
    seq = tuple(iterable)
    if not seq:
        return iter(())
    counter = count() if n is None else range(n)
    return zip(repeat_each(counter, len(seq)), cycle(seq))

def repeat_each(counter, length):
    for count in counter:
        for _ in range(length):
            yield count

def test_count_cycle_normal():
    assert list(count_cycle('AB', 3)) == [(0, 'A'), (0, 'B'), (1, 'A'), (1, 'B'), (2, 'A'), (2, 'B')]
    assert list(count_cycle([1, 2], 2)) == [(0, 1), (0, 2), (1, 1), (1, 2)]
    assert list(count_cycle(range(3), 1)) == [(0, 0), (0, 1), (0, 2)]

def test_count_cycle_infinite():
    result = list(islice(count_cycle('AB'), 6))
    assert result == [(0, 'A'), (0, 'B'), (1, 'A'), (1, 'B'), (2, 'A'), (2, 'B')]

def test_count_cycle_empty():
    assert list(count_cycle([], 3)) == []
    assert list(count_cycle('', 3)) == []

def test_count_cycle_no_n():
    result = list(islice(count_cycle('XYZ'), 9))
    assert result == [(0, 'X'), (0, 'Y'), (0, 'Z'), (1, 'X'), (1, 'Y'), (1, 'Z'), (2, 'X'), (2, 'Y'), (2, 'Z')]

def test_count_cycle_large_n():
    result = list(count_cycle('A', 100))
    assert result == [(i, 'A') for i in range(100)]

def test_count_cycle_single_item():
    assert list(count_cycle('A', 3)) == [(0, 'A'), (1, 'A'), (2, 'A')]
    assert list(count_cycle([42], 2)) == [(0, 42), (1, 42)]

def test_count_cycle_invalid_n():
    with pytest.raises(TypeError):
        list(count_cycle('AB', 'three'))
    with pytest.raises(TypeError):
        list(count_cycle('AB', None))

def test_count_cycle_non_iterable():
    with pytest.raises(TypeError):
        list(count_cycle(123, 3))
    with pytest.raises(TypeError):
        list(count_cycle(3.14, 3))

