import pytest
from itertools import islice
from sys import maxsize
from more_itertools import *
from more_itertools.more import *


class TestGetSlice:
    class MockIterable:
        def __init__(self, iterable):
            self._it = iterable
            self._cache = []

        def _get_slice(self, index):
            step = 1 if (index.step is None) else index.step
            if step > 0:
                start = 0 if (index.start is None) else index.start
                stop = maxsize if (index.stop is None) else index.stop
            elif step < 0:
                start = -1 if (index.start is None) else index.start
                stop = (-maxsize - 1) if (index.stop is None) else index.stop
            else:
                raise ValueError('slice step cannot be zero')

            if (start < 0) or (stop < 0):
                self._cache.extend(self._it)
            else:
                n = min(max(start, stop) + 1, maxsize)
                cache_len = len(self._cache)
                if n >= cache_len:
                    self._cache.extend(islice(self._it, n - cache_len))

            return list(self._cache)[index]

    def test_normal_slice(self):
        mock_iterable = self.MockIterable(range(10))
        assert mock_iterable._get_slice(slice(2, 5)) == [2, 3, 4]

    def test_empty_slice(self):
        mock_iterable = self.MockIterable(range(10))
        assert mock_iterable._get_slice(slice(5, 5)) == []

    def test_full_slice(self):
        mock_iterable = self.MockIterable(range(10))
        assert mock_iterable._get_slice(slice(0, 10)) == list(range(10))

    def test_negative_start(self):
        mock_iterable = self.MockIterable(range(10))
        assert mock_iterable._get_slice(slice(-5, None)) == [5, 6, 7, 8, 9]

    def test_negative_stop(self):
        mock_iterable = self.MockIterable(range(10))
        assert mock_iterable._get_slice(slice(None, -5)) == [0, 1, 2, 3, 4]

    def test_negative_step(self):
        mock_iterable = self.MockIterable(range(10))
        assert mock_iterable._get_slice(slice(5, 0, -1)) == [5, 4, 3, 2, 1]

    def test_step_zero(self):
        mock_iterable = self.MockIterable(range(10))
        with pytest.raises(ValueError, match='slice step cannot be zero'):
            mock_iterable._get_slice(slice(0, 5, 0))

    def test_large_range(self):
        mock_iterable = self.MockIterable(range(1000))
        assert mock_iterable._get_slice(slice(500, 505)) == [500, 501, 502, 503, 504]

    def test_large_negative_range(self):
        mock_iterable = self.MockIterable(range(1000))
        assert mock_iterable._get_slice(slice(-10, -1)) == [990, 991, 992, 993, 994, 995, 996, 997, 998, 999]

    def test_cache_behavior(self):
        mock_iterable = self.MockIterable(range(10))
        mock_iterable._get_slice(slice(0, 5))
        assert mock_iterable._cache == list(range(5))

        mock_iterable._get_slice(slice(5, 10))
        assert mock_iterable._cache == list(range(10))

    def test_cache_with_negative_start(self):
        mock_iterable = self.MockIterable(range(10))
        mock_iterable._get_slice(slice(-5, None))
        assert mock_iterable._cache == list(range(10))

    def test_cache_with_negative_stop(self):
        mock_iterable = self.MockIterable(range(10))
        mock_iterable._get_slice(slice(None, -5))
        assert mock_iterable._cache == list(range(5))

    def test_cache_with_full_negative_slice(self):
        mock_iterable = self.MockIterable(range(10))
        mock_iterable._get_slice(slice(-1, -10, -1))
        assert mock_iterable._cache == list(range(10))

