import pytest
from arrow.util import is_timestamp, normalize_timestamp


# Assuming MAX_TIMESTAMP, MAX_TIMESTAMP_MS, and MAX_TIMESTAMP_US are defined somewhere
MAX_TIMESTAMP = 1e12  # Example value
MAX_TIMESTAMP_MS = 1e15  # Example value
MAX_TIMESTAMP_US = 1e18  # Example value

def normalize_timestamp(timestamp: float) -> float:
    """Normalize millisecond and microsecond timestamps into normal timestamps."""
    if timestamp > MAX_TIMESTAMP:
        if timestamp < MAX_TIMESTAMP_MS:
            timestamp /= 1000
        elif timestamp < MAX_TIMESTAMP_US:
            timestamp /= 1_000_000
        else:
            raise ValueError(f"The specified timestamp {timestamp!r} is too large.")
    return timestamp

def test_normalize_timestamp_seconds():
    assert normalize_timestamp(1e12) == 1e12  # Normal case, already in seconds
    assert normalize_timestamp(1e13) == 1e10  # Normal case, in milliseconds
    assert normalize_timestamp(1e15) == 1e9   # Normal case, in microseconds

def test_normalize_timestamp_milliseconds():
    assert normalize_timestamp(1e14) == 1e11  # Normal case, in milliseconds
    assert normalize_timestamp(1e16) == 1e10  # Normal case, in microseconds

def test_normalize_timestamp_microseconds():
    assert normalize_timestamp(1e17) == 1e11  # Normal case, in microseconds

def test_normalize_timestamp_edge_cases():
    assert normalize_timestamp(MAX_TIMESTAMP) == MAX_TIMESTAMP  # Edge case at MAX_TIMESTAMP
    assert normalize_timestamp(MAX_TIMESTAMP_MS) == MAX_TIMESTAMP_MS / 1000  # Edge case at MAX_TIMESTAMP_MS
    assert normalize_timestamp(MAX_TIMESTAMP_US) == MAX_TIMESTAMP_US / 1_000_000  # Edge case at MAX_TIMESTAMP_US

def test_normalize_timestamp_too_large():
    with pytest.raises(ValueError, match="The specified timestamp"):
        normalize_timestamp(1e19)  # Exceeds MAX_TIMESTAMP_US

def test_normalize_timestamp_negative():
    assert normalize_timestamp(-1e12) == -1e12  # Negative timestamp, should remain unchanged

def test_normalize_timestamp_zero():
    assert normalize_timestamp(0) == 0  # Zero timestamp, should remain unchanged

def test_normalize_timestamp_small_values():
    assert normalize_timestamp(0.5) == 0.5  # Small positive value, should remain unchanged
    assert normalize_timestamp(0.001) == 0.001  # Small value in seconds, should remain unchanged
    assert normalize_timestamp(1e-6) == 1e-6  # Small value in seconds, should remain unchanged

