import pytest
from itertools import islice
from more_itertools import *
from more_itertools.more import *


def repeat_last(iterable, default=None):
    """After the *iterable* is exhausted, keep yielding its last element.

        >>> list(islice(repeat_last(range(3)), 5))
        [0, 1, 2, 2, 2]

    If the iterable is empty, yield *default* forever::

        >>> list(islice(repeat_last(range(0), 42), 5))
        [42, 42, 42, 42, 42]

    """
    item = _marker
    for item in iterable:
        yield item
    final = default if item is _marker else item
    yield from repeat(final)

_marker = object()

def test_repeat_last_normal_cases():
    assert list(islice(repeat_last(range(3)), 5)) == [0, 1, 2, 2, 2]
    assert list(islice(repeat_last([1, 2, 3]), 5)) == [1, 2, 3, 3, 3]
    assert list(islice(repeat_last('abc'), 5)) == ['a', 'b', 'c', 'c', 'c']

def test_repeat_last_empty_iterable_with_default():
    assert list(islice(repeat_last([], 42), 5)) == [42, 42, 42, 42, 42]

def test_repeat_last_empty_iterable_without_default():
    assert list(islice(repeat_last([]), 5)) == []

def test_repeat_last_single_element_iterable():
    assert list(islice(repeat_last([5]), 5)) == [5, 5, 5, 5, 5]
    assert list(islice(repeat_last('x'), 5)) == ['x', 'x', 'x', 'x', 'x']

def test_repeat_last_large_iterable():
    assert list(islice(repeat_last(range(100)), 105)) == list(range(100)) + [99, 99, 99, 99, 99]

def test_repeat_last_iterable_with_none():
    assert list(islice(repeat_last([None]), 5)) == [None, None, None, None, None]
    assert list(islice(repeat_last([], None), 5)) == [None, None, None, None, None]

def test_repeat_last_iterable_with_mixed_types():
